from flask import Flask, request, jsonify
from itsdangerous import TimedJSONWebSignatureSerializer as Serializer
import hashlib

app = Flask(__name__)
app.config["SECRET_KEY"] = "your-secret-key"

@app.route("/login", methods=["POST"])
def login():
    username = request.json.get("username")
    password = request.json.get("password")

    # Verify the user's credentials
    if username == "admin" and hashlib.sha256(password.encode()).hexdigest() == "your-hashed-password":
        # Generate a token for the user
        serializer = Serializer(app.config["SECRET_KEY"], expires_in=86400)
        token = serializer.dumps({"username": username})

        return jsonify({"token": token.decode()})
    else:
        return jsonify({"error": "Invalid credentials"}), 401

@app.route("/protected", methods=["GET"])
def protected():
    # Verify the token and get the user's username
    serializer = Serializer(app.config["SECRET_KEY"])
    try:
        data = serializer.loads(request.headers.get("Authorization"))
        username = data.get("username")
    except:
        return jsonify({"error": "Invalid token"}), 401

    # Check if the user is authorized to access this endpoint
    if username == "admin":
        return jsonify({"message": "Hello, admin!"})
    else:
        return jsonify({"error": "You are not authorized to access this endpoint"}), 403